// enginebundle.js - Fixed w/ UI Controls (pause/resume/visibility)\nclass SensitivityEngine{constructor(canvas){this.canvas=canvas;this.ctx=canvas.getContext("2d");this.width=canvas.width=window.innerWidth;this.height=canvas.height=window.innerHeight;this.sensBezier=[0.25,0.1,0.25,1];this.sensLinear=0.8;this.travaPixels=50;this.velThreshSlow=2;this.velThreshFast=15;this.noiseFilterSize=5;this.touchHistory=[];this.lastPos={x:0,y:0};this.vel={x:0,y:0};this.crosshair={x:this.width/2,y:this.height/2};this.target={x:Math.random()*this.width,y:Math.random()*this.height,r:30,hit:false};this.recoilControl=false;this.sensAdjust=true;this.aimStability=true;this.isPaused=false;this.pausedRaf=null;this.initTouch();this.loop()}getStatus(){return"Vel: "+Math.hypot(this.vel.x,this.vel.y).toFixed(1)+" px/f"}pause(){this.isPaused=true;if(this.pausedRaf)cancelAnimationFrame(this.pausedRaf)}resume(){this.isPaused=false;this.loop()}toggleVisibility(){this.canvas.style.display=this.canvas.style.display==="none"?"block":"block";if(this.canvas.style.display==="none"){this.pause()}else{this.resume()}}bezier(t,p0,p1,p2,p3){const u=1-t;return u*u*u*p0+3*u*u*t*p1+3*u*t*t*p2+t*t*t*p3}applySensitivity(delta){if(!this.sensAdjust)return delta*this.sensLinear;const norm=Math.min(Math.abs(delta)/this.travaPixels,1);const curved=this.bezier(norm,0,this.sensBezier[0],this.sensBezier[1],1)*Math.sign(delta);return curved*this.travaPixels}filterTouch(pos){this.touchHistory.push(pos);if(this.touchHistory.length>this.noiseFilterSize)this.touchHistory.shift();const avg={x:0,y:0};this.touchHistory.forEach(p=>{avg.x+=p.x;avg.y+=p.y});avg.x/=this.touchHistory.length;avg.y/=this.touchHistory.length;return avg}controlVelocity(dx,dy){const speed=Math.hypot(dx,dy);if(speed<this.velThreshSlow){dx*=0.4;dy*=0.4}else if(speed>this.velThreshFast){dx=0;dy=0}return{x:dx,y:dy}}initTouch(){this.canvas.style.touchAction="none";this.canvas.style.pointerEvents="auto";this.canvas.addEventListener("touchstart",e=>{e.preventDefault();if(e.touches[0])this.updateTouch(e.touches[0])},{passive:false});this.canvas.addEventListener("touchmove",e=>{e.preventDefault();if(e.touches[0])this.updateTouch(e.touches[0])},{passive:false});this.canvas.addEventListener("pointermove",e=>{this.updateTouch(e)},true)}updateTouch(touch){const rect=this.canvas.getBoundingClientRect();const rawX=touch.clientX-rect.left;const rawY=touch.clientY-rect.top;const filtered=this.filterTouch({x:rawX,y:rawY});const dx=filtered.x-this.lastPos.x;const dy=filtered.y-this.lastPos.y;this.lastPos={x:filtered.x,y:filtered.y};this.vel={x:dx,y:dy};const controlled=this.controlVelocity(dx,dy);const sensDx=this.applySensitivity(controlled.x);const sensDy=this.applySensitivity(controlled.y);this.crosshair.x+=sensDx;this.crosshair.y+=sensDy;this.crosshair.x=Math.max(0,Math.min(this.width,this.crosshair.x));this.crosshair.y=Math.max(0,Math.min(this.height,this.crosshair.y));const dist=Math.hypot(this.crosshair.x-this.target.x,this.crosshair.y-this.target.y);this.target.hit=dist<this.target.r}loop(){if(this.isPaused)return;this.pausedRaf=requestAnimationFrame(()=>this.loop());this.ctx.save();this.ctx.fillStyle="rgba(13,13,21,0.9)";this.ctx.fillRect(0,0,this.width,this.height);this.ctx.fillStyle=this.target.hit?"#00ff88":"#ff4444";this.ctx.beginPath();this.ctx.arc(this.target.x,this.target.y,this.target.r,0,Math.PI*2);this.ctx.fill();this.ctx.strokeStyle="#ffffff";this.ctx.lineWidth=3;this.ctx.lineCap="round";this.ctx.beginPath();this.ctx.moveTo(this.crosshair.x-25,this.crosshair.y);this.ctx.lineTo(this.crosshair.x+25,this.crosshair.y);this.ctx.moveTo(this.crosshair.x,this.crosshair.y-25);this.ctx.lineTo(this.crosshair.x,this.crosshair.y+25);this.ctx.stroke();this.ctx.fillStyle="#ffffff";this.ctx.font="bold 18px Segoe UI";this.ctx.textAlign="left";this.ctx.fillText("Engine 100% | "+this.getStatus(),15,35);if(this.target.hit){this.target.x=Math.random()*this.width;this.target.y=Math.random()*this.height}this.ctx.restore()}toggleRecoil(on){this.recoilControl=on}toggleSens(on){this.sensAdjust=on}toggleAim(on){this.aimStability=on}}let engine;window.addEventListener("load",()=>{const canvas=document.createElement("canvas");canvas.width=window.innerWidth;canvas.height=window.innerHeight;canvas.style.cssText="position:fixed;top:0;left:0;z-index:9999;touch-action:none;cursor:crosshair;pointer-events:auto";document.body.appendChild(canvas);engine=new SensitivityEngine(canvas);window.engine=engine;if("serviceWorker"in navigator)navigator.serviceWorker.register("/sw.js").then(()=>console.log("SW OK")).catch(e=>console.log("SW fail:",e))});
